SELECT COUNT(DISTINCT coach_id) AS number_of_head_coaches, role
FROM coach_seasons
WHERE role = 'Head Coach' AND season_id = 0;

SELECT award_name
FROM coach_awards
WHERE award_category = 'performance';

SELECT coach_id, AVG(win_percentage) AS average_win_percentage
FROM coach_performance
GROUP BY coach_id;

SELECT COUNT(*) AS award_count
FROM coach_awards
WHERE coach_id = 1;

SELECT MAX(win_max) AS max_wins
FROM coach_performance
WHERE season_id = 1;

SELECT SUM(total_games) AS total_coached_games
FROM coach_performance
WHERE coach_id = (SELECT coach_id FROM coaches WHERE name = 'Lester');
